import math
class Solution:
    def judgeSquareSum(self, c):
        lo, hi = 0, int(math.isqrt(c))
        while lo <= hi:
            s = lo * lo + hi * hi
            if s == c:
                return True
            if s < c:
                lo += 1
            else:
                hi -= 1
        return False

