var judgeSquareSum = function(c) {
    let lo = 0, hi = Math.floor(Math.sqrt(c));
    while (lo <= hi) {
        const s = lo * lo + hi * hi;
        if (s === c) return true;
        if (s < c) lo++;
        else hi--;
    }
    return false;
};
